{
    HeaderList A, M, N;
    int i, m = 0, n = 0;
    int x;

    Init(&A);        //初始化链表
    Init(&M);
    Init(&N);

    for (i = 0; i < 9; i++)        //给链表A插入0~9
        Insert(&A, i - 1, i);
    printf("原List:");    //输出链表A
    Output(&A);

    for (i = 0; i < 9; i++)
    {
        Find(A, i, &x);            //用查找运算遍历链表A，用x存储返回值
        if (i % 2 == 1)
        {
            Insert(&M, m - 1, x);    //下标为奇数时，将元素添加至链表M
            m++;    //m表示链表M的下标
        }
        else
