            Insert(&N, n - 1, x);    //下标为偶数时，加元素添加至链表N
            n++;    //n表示链表N的下标
        }
    }

    printf("\nList（奇数下标）:");
    Output(&M);
    printf("\nList（偶数下标）:");
    Output(&N);
}
```

